        var envVar = "KREUZBERG_" + feature.Replace("-", "_").ToUpperInvariant() + "_DISABLED";
        var flag = Environment.GetEnvironmentVariable(envVar);
        if (flag == "1" || (flag != null && flag.Equals("true", StringComparison.OrdinalIgnoreCase)))
