                if (!found)
                    return false;
            }
            return true;
        }

        return false;
    }

    public static void AssertChunks(
        ExtractionResult result,
        int? minCount,
        int? maxCount,
        bool? eachHasContent,
        bool? eachHasEmbedding,
        bool? eachHasHeadingContext = null,
        bool? eachHasChunkType = null,
        bool? contentStartsWithHeading = null)
    {
        var chunks = result.Chunks;
        if (chunks is null)
        {
            throw new XunitException("Expected chunks but got null");
        }
        var count = chunks.Count;
        if (minCount.HasValue && count < minCount.Value)
        {
            throw new XunitException($"Expected at least {minCount.Value} chunks, found {count}");
        }
        if (maxCount.HasValue && count > maxCount.Value)
        {
            throw new XunitException($"Expected at most {maxCount.Value} chunks, found {count}");
        }
        if (eachHasContent == true)
        {
            for (var i = 0; i < chunks.Count; i++)
            {
                if (string.IsNullOrEmpty(chunks[i].Content))
                {
                    throw new XunitException($"Chunk {i} has no content");
                }
            }
        }
        if (eachHasEmbedding == true)
        {
            for (var i = 0; i < chunks.Count; i++)
            {
                if (chunks[i].Embedding is null || chunks[i].Embedding!.Length == 0)
                {
                    throw new XunitException($"Chunk {i} has no embedding");
                }
            }
        }
        if (eachHasHeadingContext == true)
        {
            for (var i = 0; i < chunks.Count; i++)
            {
                if (chunks[i].Metadata?.HeadingContext is null)
                {
                    throw new XunitException($"Chunk {i} has no heading_context");
                }
            }
        }
        if (eachHasHeadingContext == false)
        {
            for (var i = 0; i < chunks.Count; i++)
            {
                if (chunks[i].Metadata?.HeadingContext is not null)
                {
                    throw new XunitException($"Chunk {i} should have no heading_context");
                }
            }
        }
        if (eachHasChunkType == true)
        {
            for (var i = 0; i < chunks.Count; i++)
            {
                var type = chunks[i].ChunkType;
                if (string.IsNullOrEmpty(type) || type == "unknown")
                {
                    throw new XunitException($"Chunk {i} has no specific chunk_type, got {type}");
                }
            }
        }
        if (contentStartsWithHeading == true)
        {
            var headingChar = new string(new[] { (char)35 });
            for (var i = 0; i < chunks.Count; i++)
            {
                if (chunks[i].Metadata?.HeadingContext is null) continue;
                if (string.IsNullOrEmpty(chunks[i].Content) || !chunks[i].Content!.StartsWith(headingChar))
                {
                    throw new XunitException($"Chunk {i} content does not start with a heading");
                }
            }
        }
    }

