    public static void AssertQualityScore(ExtractionResult result, bool? hasScore, double? minScore, double? maxScore)
    {
        if (hasScore == true)
        {
            if (result.QualityScore is null)
            {
                throw new XunitException("Expected quality score to be present");
            }
        }
        if (minScore.HasValue && result.QualityScore.HasValue)
        {
            if (result.QualityScore.Value < minScore.Value)
            {
                throw new XunitException($"Expected quality score >= {minScore.Value}, got {result.QualityScore.Value}");
            }
        }
        if (maxScore.HasValue && result.QualityScore.HasValue)
        {
            if (result.QualityScore.Value > maxScore.Value)
            {
                throw new XunitException($"Expected quality score <= {maxScore.Value}, got {result.QualityScore.Value}");
            }
        }
    }

    public static void AssertProcessingWarnings(ExtractionResult result, int? maxCount, bool? isEmpty)
    {
        var warnings = result.ProcessingWarnings;
        var count = warnings?.Count ?? 0;
        if (isEmpty == true && count != 0)
        {
            throw new XunitException($"Expected processing warnings to be empty, got {count}");
        }
        if (maxCount.HasValue && count > maxCount.Value)
        {
            throw new XunitException($"Expected at most {maxCount.Value} processing warnings, got {count}");
        }
    }

    public static void AssertDjotContent(ExtractionResult result, bool? hasContent, int? minBlocks)
    {
        var djotContent = result.DjotContent;
        if (hasContent == true)
        {
            if (djotContent is null || string.IsNullOrEmpty(djotContent.PlainText))
            {
                throw new XunitException("Expected djot content to be present");
            }
        }
        if (minBlocks.HasValue && djotContent is not null)
        {
            var blockCount = djotContent.Blocks?.Count ?? 0;
            if (blockCount < minBlocks.Value)
            {
                throw new XunitException($"Expected at least {minBlocks.Value} djot blocks, got {blockCount}");
            }
        }
    }

    public static void AssertAnnotations(ExtractionResult result, bool hasAnnotations, int? minCount)
    {
        var annotations = result.Annotations;
        if (hasAnnotations)
        {
            if (annotations is null || annotations.Count == 0)
            {
                throw new XunitException("Expected annotations to be present and non-empty");
            }
        }
        if (annotations is not null && minCount.HasValue)
        {
            if (annotations.Count < minCount.Value)
            {
                throw new XunitException($"Expected at least {minCount.Value} annotations, got {annotations.Count}");
            }
        }
    }

    public static void AssertStructuredOutput(ExtractionResult result, bool? hasOutput, bool? validatesSchema, string[]? fieldExists)
    {
        var output = result.StructuredOutput;
        if (hasOutput == true)
        {
            Assert.NotNull(output);
        }
        else if (hasOutput == false)
        {
            Assert.Null(output);
        }
        if (output is not null && validatesSchema == true)
        {
            Assert.NotEmpty(output);
        }
        if (output is not null && fieldExists is not null)
        {
            foreach (var field in fieldExists)
            {
                Assert.True(output.ContainsKey(field), $"Expected structured output to contain field '{field}'");
            }
        }
    }

    public static void AssertIsPng(byte[] data)
    {
        Assert.NotNull(data);
        Assert.True(data.Length >= 4, $"Data too short for PNG: {data.Length} bytes");
        Assert.True(data[0] == 0x89 && data[1] == 0x50 && data[2] == 0x4E && data[3] == 0x47,
            $"Missing PNG magic bytes, got: [{data[0]:X2}, {data[1]:X2}, {data[2]:X2}, {data[3]:X2}]");
    }

    public static void AssertMinByteLength(byte[] data, int minLength)
    {
        Assert.NotNull(data);
        Assert.True(data.Length >= minLength, $"Expected at least {minLength} bytes, got {data.Length}");
    }

    public static void AssertEmbedResult(IEnumerable<float[]> results, int count, int dimensions, bool noNan, bool noInf, bool nonZero)
    {
        Assert.NotNull(results);
        var resultList = results.ToList();
        if (count >= 0)
        {
            Assert.Equal(count, resultList.Count);
        }
        if (resultList.Count > 0)
        {
            for (int i = 0; i < resultList.Count; i++)
            {
                var vector = resultList[i];
                Assert.NotNull(vector);
                if (dimensions > 0)
                {
                    Assert.Equal(dimensions, vector.Length);
                }

                bool hasNonZero = false;
                for (int j = 0; j < vector.Length; j++)
                {
                    float v = vector[j];
                    if (noNan)
                    {
                        Assert.False(float.IsNaN(v), $"Vector {i} element {j} is NaN");
                    }
                    if (noInf)
                    {
                        Assert.False(float.IsInfinity(v), $"Vector {i} element {j} is Infinity");
                    }
                    if (v != 0.0f)
                    {
                        hasNonZero = true;
                    }
                }
                if (nonZero)
                {
                    Assert.True(hasNonZero, $"Vector {i} is all zeros");
                }
            }
        }
    }
}
